CREATE OR REPLACE FUNCTION fpa_total_share (as_memno char, ai_year bigint,ai_month bigint,ai_seq bigint,as_code char) RETURNS bigint AS $body$
DECLARE

  ldc_share sc_kep_t_monthly_receive_det.money_amount_not%type;

BEGIN
  select sum(CASE WHEN trim(both sc_kep_t_monthly_receive_det.keeping_type_code)=as_code THEN money_amount_not  ELSE 0 END )
  into STRICT ldc_share
  from sc_kep_t_monthly_receive_det
  where (membership_no = as_memno)
  and (receive_year = ai_year)
  and (receive_month = ai_month)
  and (seq_no = ai_seq);

  if coalesce(ldc_share::text, '') = '' then ldc_share := 0;end if;

  return coalesce(ldc_share,0);
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
